// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:35。佐伯把案例卡排成三列。每張卡白紙黑字。沒有照片。沒有全名。代號在最上面。下面是年齡、失蹤日數、材料類型。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不讓家屬輪流講故事。他說過一次：故事會讓人記住情緒，忘記日期。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "在看案例以前，先把證據品質分清楚。不是所有日期都一樣可靠。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿出一張紙。上面是他自己畫的表格。三欄。三級。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "強。外部單位還保存當時收到的附件、掃描件，或者有能對應內容的回覆。這種能證明的不只是檔案存在，還包括部分內容在那一天已經被外面的人看見。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "中。外部系統保存檔名、長度和提交日期。但目前手上的播放副本是不是和當時上傳的完全一樣，還要再確認。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "弱。只有家庭原始裝置或後來整理的副本。暫列參考。不作時間證明。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在把證據分級。像查核報告一樣。不是所有來源都同等可靠。不是所有日期都代表同樣的事。檔案建立日期可以改。但外部單位收到的時間，改不了那麼容易。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把那張表格壓在桌面中央。然後他補了一段。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "還有一件事。很多人問過，為什麼這麼多家庭都有睡夢錄音。不是巧合。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了一圈房間。沒有人反駁。有人點了一下頭。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不同名稱的睡眠研究、學校輔導、醫療追蹤，都曾經要求家長記錄異常夜醒、夢話或醒後語句。所以很多家庭都有錄音。這本身既可能保存了什麼，也可能表示這些孩子曾經接觸過同一類研究流程。兩種都要保留。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他把「為什麼都有錄音」和「錄音可能證明什麼」分開了。有錄音不代表錄音內容是真的。有錄音只代表有人被要求錄。被誰要求？不同名稱的研究。不同單位。可是要求的方式一樣。記錄的東西一樣。這本身也是一條線。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯指向第一張案例卡。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "案例A。代號葵。十四歲。睡眠健康檢查後失蹤。黑色海圖像。最後訊息不像本人。失蹤約第四十二日。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪已經知道葵。她之前見過那張影印紙。咖啡漬。折痕。被太多人翻過。可是佐伯不讓她用已經知道的東西當新證據。他在基線卡上寫得很清楚：看過葵圖以後才知道的，不算獨立。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "這個案例的關鍵不在圖。在郵件。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從卡片下方抽出一張列印。寄件匣截圖。日期。收件人。學校輔導老師。附件名稱。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "圖像和一段睡夢錄音，在家屬群成立以前，已經作為附件電郵給學校輔導老師。寄件匣還保留著附件。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他翻到另一張。老師的回覆。日期比家屬群成立更早。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "老師的回覆裡提到一句：「後半像有地名，但聽不清。」", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯老師聽到了。不只是檔案存在。是有人在那天打開了附件，聽了錄音，而且聽到了後半段有什麼。他聽不清。但他注意到了。這不是家屬事後補造的。這是外部的人在這些家庭互相認識以前，就已經收到並且部分回應過的東西。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "這個案例列為強證據。寄件匣保留附件，老師回覆可對應部分內容。能比較有力地證明材料不是家屬相識後才補造的。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把案例A的卡片往左推。在右上角寫了一個「強」字。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他指向第二張。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "案例B。代號蓮。十六歲。參加學校轉介的壓力反應追蹤。失蹤約第二十四日。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說「蓮」的時候，語氣變平了。不是冷漠。是把情緒壓進文件格式裡的那種平。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯蓮。佐伯蓮。他的兒子。他在用自己的兒子當案例。他沒有跳過。沒有交給別人講。他把自己的孩子也放進同一套分級裡。強就是強。弱就是弱。不因為是他的兒子就升級。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "失蹤前常在清晨驚醒。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停了一下。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "都在六點多。精確時間我還在重查。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯六點多。他沒有說幾分。他說「還在重查」。如果他知道精確時間，他不會在這裡說。他要等外部紀錄確認。他要等能對應的東西。他不會用自己的記憶當證據。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯從卡片下方抽出一張掃描列印。學校健康問卷。正面是印刷表格。背面——", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "七條平行線。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "直的。從上到下。間距不太均勻。像用尺畫過，但沒有畫完就停了。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "問卷背面。七條線。校方掃描版本留有日期。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他指了一下掃描列印右下角的時間戳。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "這個日期早於共用資料夾建立。列為強證據。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他翻出另一張紙。上面只有幾行文字。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "完整的睡夢錄音，只有我家原始裝置上有。外部單位只收到其中一小段文字說明。不是音檔。是文字。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把那張紙放回卡片旁邊。在右上角寫了一個字。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "弱。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "問卷圖像，強。完整錄音，弱。不能混在一起。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在自己的兒子身上畫了一條線。強的部分他承認。弱的部分他也承認。他不會因為那是蓮的錄音，就把它當成強證據。他比任何人都想聽那段錄音裡有答案。可是正因為這樣，他更不能讓自己相信得太快。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把案例B的卡片排好。強與弱並列。沒有合併。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他指向第三張。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "案例C。代號美空。十三歲。曾失蹤兩日。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "藤川真理的手在桌面下動了一下。像在摸一個不在這裡的東西。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "交通卡與車站畫面顯示她曾自行移動。在外縣市地區醫療設施入口附近被發現。身上沒有明顯外傷。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他頓了一下。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "至今未恢復清醒。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡安靜了幾秒。不是儀式性的安靜。是所有人都知道這句話的重量，沒有人需要再解釋的那種安靜。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "本人被尋獲後，失蹤程序結束。後續被拆成兩條。一條是未成年人自行外出。一條是不明原因意識障礙。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯拆開了。失蹤的時候是一個案子。人找到了，就不是失蹤了。可是她沒有醒。所以失蹤案結束了，意識障礙另開一條。自行外出又另開一條。一個孩子的事情，被分進三個不同的制度欄位。每一個欄位都只看自己那部分。沒有一個欄位看全部。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "失蹤前的夢話錄音，曾經上傳到醫院病患系統。系統保留檔名、長度和提交日期。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他抽出一張列印。醫院系統截圖。不是完整錄音。是上傳紀錄。檔名。時長。提交時間。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "門診紀錄裡也引用過其中一句。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他念出來。語氣像在讀病歷。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "「不要讓海翻過來。」", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不要讓海翻過來。海。又是海。黑色海。倒月。七條線。現在又多了一句話。不要讓海翻過來。這不是圖。這是語句。是夢話。是被醫院門診紀錄引用過的夢話。在上傳的時候就已經存在。不是家屬後來拼的。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "這個案例列為中等偏強。提交時間和部分內容可以由醫療紀錄確認。但會議上播放的副本是否和當時附件逐秒相同，還要進一步核對。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在卡片右上角寫了「中」字。然後在旁邊加了一個小小的「偏強」。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "藤川真理一直沒有說話。她看著那張案例卡。看著代號美空。看著那個「中」字。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她開口了。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.FujikawaMari, character: "藤川真理", dialogue: "警察說她回來了。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.FujikawaMari_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音像在陳述天氣。已經說過太多次。情緒被磨平了。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.FujikawaMari, character: "藤川真理", dialogue: "醫院說她還活著。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.FujikawaMari_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停了一下。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.FujikawaMari, character: "藤川真理", dialogue: "可是沒有一個人能告訴我，她去哪裡了。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.FujikawaMari_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這句話落在桌面上。沒有回音。沒有人接。不是因為沒有人在乎。是因為房間裡每個人都聽過某個版本的同樣的話。只是主詞不同。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯三種。三種沒有回來。葵失蹤了，四十二天，沒有找到。蓮失蹤了，二十四天，沒有找到。美空被找到了。身體回來了。可是她沒有醒。她去了哪裡？沒有人知道。警察說結案了。醫院說還活著。可是她去哪裡了——這個問題，沒有任何一個制度欄位能回答。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著那三張案例卡。排成一列。強。弱。中。三個孩子。三種結果。三套不同的制度分類。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯共同點。我能確認的共同點只能到這裡。年齡接近。都接觸過不同名稱的睡眠、健康或壓力追蹤。失蹤或昏迷前都留下過相似材料。官方案件被分到不同制度欄位。至少部分材料有群體成立以前的外部時間證據。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不能再往前了。我不能把這三個案子畫成一個完整的國家系統。我不能說這些研究是同一個來源。我不能說這些孩子被同一個東西挑選。我看到的只是碎片。碎片之間有形狀相似的邊緣。但形狀相似不等於來自同一塊。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:05。佐伯把三張案例卡排好。強。弱。中。並列。沒有合併成一個結論。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看了澪一眼。像在確認她有沒有開始往前跑太快。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "妳看到的就是這些。不要在今天把它們拼成一個更大的東西。", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.SaekiTatsuya_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有回答。她把視線從案例卡上移開。落在桌面邊緣——那裡有一疊她還沒翻過的紙。案例卡的反面。每一張卡的背面都有一個欄位。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "欄位名稱是手寫的。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "孩子自行留下記號。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯孩子自行留下記號。每一張案例卡背面都有這一欄。有些是空的。有些填了。填了的那些——", background: Background.Chapter_11_Ch11_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有繼續看下去。她想到了自己帶來的那個信封。", background: Background.Chapter_11_Ch11_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "20:10。會議室的燈還亮著。三張案例卡排在桌上。三種沒有回來的孩子。三種被制度拆開的案子。和一個還沒被打開的信封。", background: Background.Chapter_11_Ch11_Act5_S0 },
];
